// SPDX-License-Identifier: Apache-2.0

package chisel3.internal.firrtl

import chisel3.{Placeholder => _, _}
import chisel3.experimental.{
  Analog,
  BaseModule,
  HasTypeAlias,
  NoSourceInfo,
  SourceInfo,
  SourceLine,
  UnlocatableSourceInfo
}
import chisel3.properties.Property
import firrtl.{ir => fir}
import firrtl.annotations.{Annotation, JsonProtocol}
import chisel3.internal.{castToInt, throwException, HasId}
import chisel3.internal.firrtl.ir._
import chisel3.EnumType
import scala.annotation.tailrec
import scala.collection.immutable.{Queue, VectorBuilder, VectorMap}

private[chisel3] object Serializer {
  private val NewLine = '\n'
  private val Indent = "  "

  // The version supported by the serializer.
  val version = "7.0.0"

  def getRef(id: HasId, sourceInfo: SourceInfo): Arg =
    id.getOptionRef.getOrElse {
      val module = id._parent.map(m => s" '$id' was defined in module '$m'.").getOrElse("")
      val loc = sourceInfo.makeMessage(" " + _)
      reportInternalError(s"Could not get ref for '$id'$loc!$module")
    }

  /** Generate a legal FIRRTL name. */
  private def legalize(name: String): String = name match {
    // If the name starts with a digit, then escape it with backticks.
    case _ if name.head.isDigit => s"`$name`"
    case _                      => name
  }

  /** create a new line with the appropriate indent */
  private def newLineAndIndent(inc: Int = 0)(implicit b: StringBuilder, indent: Int): Unit = {
    b += NewLine; doIndent(inc)
  }

  private def newLineNoIndent()(implicit b: StringBuilder): Unit = b += NewLine

  /** create indent, inc allows for a temporary increment */
  private def doIndent(inc: Int = 0)(implicit b: StringBuilder, indent: Int): Unit = {
    (0 until (indent + inc)).foreach { _ => b ++= Indent }
  }

  /** Serialize the given text as a "quoted" string. */
  private def quote(text: String)(implicit b: StringBuilder): Unit = {
    b ++= "\""
    b ++= text

    (ChiselStage.emitCHIRRTL(new RawModule {}, Array("-ll", "info")) should not).include("LogLevelAnnotation")
  }

  it("should allow remapping one layer to another") {
    val chirrtl = ChiselStage.emitCHIRRTL(
      new ChiselStageSpec.LayerRemappingTest,
      Array("--remap-layer", "circtTests.stage.ChiselStageSpec$A$,circtTests.stage.ChiselStageSpec$B$")
    )
    chirrtl should include("output out : Probe<UInt<1>, B>")
    chirrtl should include("layer B")
    chirrtl should include("layerblock B")
  }

  it("should allow remapping of printfs in Verification.Debug to Verification") {
    ChiselStage
      .emitCHIRRTL(
        new ChiselStageSpec.LayerRemappingTestPrintf,
        Array("--remap-layer", "chisel3.layers.Verification$Debug$,chisel3.layers.Verification$")
      )
      .fileCheck("-implicit-check-not='layerblock Debug'") {
        """|CHECK:      layerblock Verification :
           |CHECK-NEXT:   printf
           |""".stripMargin
      }
  }

  it("should suppress source info with --no-source-info") {
    // Sanity check source locators are presetn by default
    ChiselStage.emitCHIRRTL(new ChiselStageSpec.Foo).fileCheck()("CHECK: @[")

    // Check that flag suppresses source locators
    ChiselStage.emitCHIRRTL(new ChiselStageSpec.Foo, Array("--no-source-info")).fileCheck()("CHECK-NOT: @[")
  }
}

  phase
    .transform(annos)
    .collectFirst { case a: ChiselCircuitAnnotation => a.elaboratedCircuit }
    .get
}

/** Elaborate a Chisel circuit into a CHIRRTL string */
def emitCHIRRTL(
  gen:  => RawModule,
  args: Array[String] = Array.empty
): String = {
  val annos = Seq(
    ChiselGeneratorAnnotation(() => gen),
    CIRCTTargetAnnotation(CIRCTTarget.CHIRRTL)
  ) ++ (new Shell("circt")).parse(args)

  val resultAnnos = phase.transform(annos)

  var elaboratedCircuit: Option[ElaboratedCircuit] = None
  val inFileAnnos = resultAnnos.flatMap {
    case a: ChiselCircuitAnnotation =>
      elaboratedCircuit = Some(a.elaboratedCircuit)
      None
    case _: Unserializable     => None
    case _: CustomFileEmission => None
    case a => Some(a)
  }
  elaboratedCircuit.get.serialize(inFileAnnos)
}

/** Elaborates a Chisel circuit and emits it to a file
  *
  * @param gen  a call-by-name Chisel module
  * @param args additional command line arguments to pass to Chisel
  */
def emitCHIRRTLFile(
  gen:  => RawModule,
  args: Array[String] = Array.empty
): AnnotationSeq = {
  (new circt.stage.ChiselStage).execute(
    Array("--target", "chirrtl") ++ args,
    Seq(ChiselGeneratorAnnotation(() => gen))
  )
}
